selector_to_html = {"a[href=\"#sistema-masa-resorte-amortiguador-sobreamortiguado\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema masa resorte amortiguador (sobreamortiguado)<a class=\"headerlink\" href=\"#sistema-masa-resorte-amortiguador-sobreamortiguado\" title=\"Link to this heading\">#</a></h1><h2>Modelo cl\u00e1sico<a class=\"headerlink\" href=\"#modelo-clasico\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#funcion-objetivo-para-realizar-la-optimizacion\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Funci\u00f3n objetivo para realizar la optimizaci\u00f3n<a class=\"headerlink\" href=\"#funcion-objetivo-para-realizar-la-optimizacion\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#equation-bd0e9245-80eb-434b-9bc2-17ad566ce6d2\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-bd0e9245-80eb-434b-9bc2-17ad566ce6d2\">\n\\[\\begin{equation}\n m\\lambda^2 + c\\lambda + k = 0,\n\\end{equation}\\]</div>", "a[href=\"#sistema-masa-resorte-amortiguador\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema masa resorte amortiguador<a class=\"headerlink\" href=\"#sistema-masa-resorte-amortiguador\" title=\"Link to this heading\">#</a></h1><p>Un <strong>sistema masa resorte amortiguador</strong> consta de tres componentes esenciales</p>", "a[href=\"#perfil-de-verosimilitud-para-sigma\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Perfil de verosimilitud para <span class=\"math notranslate nohighlight\">\\(\\sigma\\)</span><a class=\"headerlink\" href=\"#perfil-de-verosimilitud-para-sigma\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#optimizacion-multietapa\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Optimizaci\u00f3n multietapa<a class=\"headerlink\" href=\"#optimizacion-multietapa\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#componentes-de-fuerza\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Componentes de Fuerza<a class=\"headerlink\" href=\"#componentes-de-fuerza\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#sistema-subamortiguado-0-zeta-1\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema subamortiguado (<span class=\"math notranslate nohighlight\">\\(0 &lt; \\zeta &lt; 1\\)</span>)<a class=\"headerlink\" href=\"#sistema-subamortiguado-0-zeta-1\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#equation-c9ceb100-600c-48bb-a62c-88907dfe69ed\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-c9ceb100-600c-48bb-a62c-88907dfe69ed\">\n\\[\\begin{equation}\n E(t) = \\underbrace{\\frac{1}{2}m\\dot{x}^2}_{\\text{Cin\u00e9tica}} + \\underbrace{\\frac{1}{2}kx^2}_{\\text{Potencial}} + \\underbrace{\\int_0^t c\\dot{x}^2\\,dt}_{\\text{Disipada}}\n\\end{equation}\\]</div>", "a[href=\"#interpretacion-fisica\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Interpretaci\u00f3n F\u00edsica<a class=\"headerlink\" href=\"#interpretacion-fisica\" title=\"Link to this heading\">#</a></h2><h3>Balance de Energ\u00eda<a class=\"headerlink\" href=\"#balance-de-energia\" title=\"Link to this heading\">#</a></h3><p><strong>Energ\u00eda Total = Energ\u00eda Cin\u00e9tica + Energ\u00eda Potencial + Energ\u00eda Disipada</strong></p>", "a[href=\"#parametros-adimensionales\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Par\u00e1metros adimensionales<a class=\"headerlink\" href=\"#parametros-adimensionales\" title=\"Link to this heading\">#</a></h3><p><strong>Frecuencia Natural</strong></p>", "a[href=\"#equation-73fbd182-2e62-466c-9f20-679c8f4ac888\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-73fbd182-2e62-466c-9f20-679c8f4ac888\">\n\\[\\begin{equation}\n \\omega_n = \\sqrt{\\frac{k}{m}} \\quad \\text{[rad/s]}.\n\\end{equation}\\]</div>", "a[href=\"#equation-b971c482-e8a0-4c4c-afc6-f312fe54faf3\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-b971c482-e8a0-4c4c-afc6-f312fe54faf3\">\n\\[\\begin{equation}\n x(t) = (A + Bt)e^{-\\omega_n t}.\n\\end{equation}\\]</div>", "a[href=\"#equation-84fcdecb-058b-4a43-a0af-5b9f43ca9126\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-84fcdecb-058b-4a43-a0af-5b9f43ca9126\">\n\\[\\begin{equation}\n \\zeta = \\frac{c}{2\\sqrt{km}}.\n\\end{equation}\\]</div>", "a[href=\"#ecuacion-caracteristica-del-sistema\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Ecuaci\u00f3n caracter\u00edstica del sistema<a class=\"headerlink\" href=\"#ecuacion-caracteristica-del-sistema\" title=\"Link to this heading\">#</a></h3><p>Al sustituir <span class=\"math notranslate nohighlight\">\\(x(t) = e^{\\lambda t}\\)</span> se obtiene:</p>", "a[href=\"#equation-2f3b0559-f1a4-44a2-a6bd-e050adc8f650\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-2f3b0559-f1a4-44a2-a6bd-e050adc8f650\">\n\\[\\begin{equation}\n \\lambda_{1,2} = -\\frac{c}{2m} \\pm \\sqrt{\\left(\\frac{c}{2m}\\right)^2 - \\frac{k}{m}}.\n\\end{equation}\\]</div>", "a[href=\"#sistema-con-amortiguamiento-critico-zeta-1\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema con amortiguamiento cr\u00edtico (<span class=\"math notranslate nohighlight\">\\(\\zeta = 1\\)</span>)<a class=\"headerlink\" href=\"#sistema-con-amortiguamiento-critico-zeta-1\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#sistema-no-amortiguado-zeta-0\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema no amortiguado (<span class=\"math notranslate nohighlight\">\\(\\zeta = 0\\)</span>)<a class=\"headerlink\" href=\"#sistema-no-amortiguado-zeta-0\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#equation-29cca9cf-3deb-4347-a6ef-ba99d5644add\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-29cca9cf-3deb-4347-a6ef-ba99d5644add\">\n\\[\\begin{equation}\n x(t) = Ae^{\\lambda_1 t} + Be^{\\lambda_2 t}.\n\\end{equation}\\]</div>", "a[href=\"#equation-093792ca-6d91-401b-826a-6970ce2c2d7c\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-093792ca-6d91-401b-826a-6970ce2c2d7c\">\n\\[\\begin{equation}\n x(t) = A\\cos(\\omega_n t) + B\\sin(\\omega_n t).\n\\end{equation}\\]</div>", "a[href=\"#equation-facaa3b6-abdb-46bb-bb31-390ad09bdcd0\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-facaa3b6-abdb-46bb-bb31-390ad09bdcd0\">\n\\[\\begin{equation}\n m\\frac{d^2x}{dt^2} + c\\frac{dx}{dt} + kx = 0,\n\\end{equation}\\]</div>", "a[href=\"#equation-4475567e-d2b6-4a87-81f8-e3577432d4bb\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-4475567e-d2b6-4a87-81f8-e3577432d4bb\">\n\\[\\begin{equation}\n \\omega_d = \\omega_n\\sqrt{1-\\zeta^2} \\quad \\text{(para } \\zeta &lt; 1\\text{)}.\n\\end{equation}\\]</div>", "a[href=\"#graficacion-del-ajuste-optimizado-vs-datos-sinteticos\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Graficaci\u00f3n del ajuste optimizado vs. datos sint\u00e9ticos<a class=\"headerlink\" href=\"#graficacion-del-ajuste-optimizado-vs-datos-sinteticos\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#equation-eb5e0eeb-7d6d-45e1-bf6e-2c3a37f95090\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-eb5e0eeb-7d6d-45e1-bf6e-2c3a37f95090\">\n\\[\\begin{equation}\n \\frac{1}{\\sigma^{1-\\alpha}}~ {}^{K}\\mathcal{D}_{t}^{\\alpha}~ f(t) = \\frac{1}{\\sigma^{1-\\alpha}} t^{1-\\alpha} \\frac{df}{dt},\n\\end{equation}\\]</div>", "a[href=\"#ejemplo-de-parametros-de-simulacion\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Ejemplo de Par\u00e1metros de Simulaci\u00f3n<a class=\"headerlink\" href=\"#ejemplo-de-parametros-de-simulacion\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#superposicion-del-modelo-clasico-y-el-modelo-conformable\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Superposici\u00f3n del modelo cl\u00e1sico y el modelo conformable<a class=\"headerlink\" href=\"#superposicion-del-modelo-clasico-y-el-modelo-conformable\" title=\"Link to this heading\">#</a></h2><p>Con un valor de <span class=\"math notranslate nohighlight\">\\(\\alpha\\)</span>, el modelo conformable replica el comportamiento que presentar\u00eda el modelo cl\u00e1sico. Para profundizar en la validaci\u00f3n del modelo, es preciso considerar tambi\u00e9n la inclusi\u00f3n de la variable <span class=\"math notranslate nohighlight\">\\(\\sigma\\)</span>. Esto es</p>", "a[href=\"#ecuacion-diferencial-gobernante\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Ecuaci\u00f3n diferencial gobernante<a class=\"headerlink\" href=\"#ecuacion-diferencial-gobernante\" title=\"Link to this heading\">#</a></h3><p>El sistema se rige por la segunda Ley de Newton</p>", "a[href=\"#balance-de-energia\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Balance de Energ\u00eda<a class=\"headerlink\" href=\"#balance-de-energia\" title=\"Link to this heading\">#</a></h3><p><strong>Energ\u00eda Total = Energ\u00eda Cin\u00e9tica + Energ\u00eda Potencial + Energ\u00eda Disipada</strong></p>", "a[href=\"#modelo-clasico\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modelo cl\u00e1sico<a class=\"headerlink\" href=\"#modelo-clasico\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#modelo-matematico\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modelo Matem\u00e1tico<a class=\"headerlink\" href=\"#modelo-matematico\" title=\"Link to this heading\">#</a></h2><h3>Ecuaci\u00f3n diferencial gobernante<a class=\"headerlink\" href=\"#ecuacion-diferencial-gobernante\" title=\"Link to this heading\">#</a></h3><p>El sistema se rige por la segunda Ley de Newton</p>", "a[href=\"#sistema-sobreamortiguado-zeta-1\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema sobreamortiguado (<span class=\"math notranslate nohighlight\">\\(\\zeta &gt; 1\\)</span>)<a class=\"headerlink\" href=\"#sistema-sobreamortiguado-zeta-1\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#equation-adbcfc99-62ff-4644-84df-30de86a9a1f9\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-adbcfc99-62ff-4644-84df-30de86a9a1f9\">\n\\[\\begin{equation}\n x(t) = e^{-\\zeta\\omega_n t}\\left[A\\cos(\\omega_d t) + B\\sin(\\omega_d t)\\right].\n\\end{equation}\\]</div>", "a[href=\"#obtencion-de-datos\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Obtenci\u00f3n de datos<a class=\"headerlink\" href=\"#obtencion-de-datos\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#tipos-de-solucion-segun-la-razon-de-amortiguamiento\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Tipos de soluci\u00f3n seg\u00fan la raz\u00f3n de amortiguamiento<a class=\"headerlink\" href=\"#tipos-de-solucion-segun-la-razon-de-amortiguamiento\" title=\"Link to this heading\">#</a></h2><h3>Sistema no amortiguado (<span class=\"math notranslate nohighlight\">\\(\\zeta = 0\\)</span>)<a class=\"headerlink\" href=\"#sistema-no-amortiguado-zeta-0\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#carga-de-datos-experimentales-y-preparacion-para-el-modelado-conformable\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Carga de datos experimentales y preparaci\u00f3n para el modelado conformable<a class=\"headerlink\" href=\"#carga-de-datos-experimentales-y-preparacion-para-el-modelado-conformable\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#modelo-conformable-con-alpha-to-1\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modelo conformable con <span class=\"math notranslate nohighlight\">\\(\\alpha \\to 1\\)</span><a class=\"headerlink\" href=\"#modelo-conformable-con-alpha-to-1\" title=\"Link to this heading\">#</a></h2><p>Establecemos <span class=\"math notranslate nohighlight\">\\(\\alpha\\)</span> en un valor extremadamente cercano a 1 (<span class=\"math notranslate nohighlight\">\\(0.99999\\)</span>) y comparamos el resultado con el modelo cl\u00e1sico. La diferencia deber\u00eda ser m\u00ednima, lo que confirma que la implementaci\u00f3n conformable es correcta.</p>", "a[href=\"#modelo-conformable-con-sigma\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modelo conformable con <span class=\"math notranslate nohighlight\">\\(\\sigma\\)</span><a class=\"headerlink\" href=\"#modelo-conformable-con-sigma\" title=\"Link to this heading\">#</a></h2><h3>Funci\u00f3n objetivo para realizar la optimizaci\u00f3n<a class=\"headerlink\" href=\"#funcion-objetivo-para-realizar-la-optimizacion\" title=\"Link to this heading\">#</a></h3>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: false,
                placement: 'auto-start', maxWidth: 500, interactive: true, boundary: document.body, appendTo: document.body,
                onShow(instance) {MathJax.typesetPromise([instance.popper]).then(() => {var isFirefox=typeof InstallTrigger!=='undefined';if(isFirefox&&window.MathJax&&MathJax.startup&&MathJax.startup.output&&MathJax.startup.output.name==="SVG"){const svgs=instance.popper.querySelectorAll('svg');svgs.forEach(svg=>{let bbox=svg.getBBox(),x=bbox.x,y=bbox.y,width=bbox.width,height=bbox.height;svg.setAttribute('width',width);svg.setAttribute('height',height);svg.setAttribute('viewBox',`${x} ${y} ${width} ${height}`);});let rescale=0.015;svgs.forEach(svg=>{let bbox=svg.getBBox(),width=bbox.width,height=bbox.height;svg.setAttribute('width',width*rescale);svg.setAttribute('height',height*rescale);});}});},
            });
        };
    };
    console.log("tippy tips loaded!");
};
